sql:
SELECT AVG(pledged) AS average_pledged_amount
FROM projects
WHERE outcomes = 'successful';

SELECT name
FROM projects
WHERE pledged = (SELECT MAX(pledged) FROM projects);

SELECT name, pledged AS total_pledged
FROM projects
WHERE percentage_funded >= 100;

external_knowledge:
- "shining stars" refers to projects with significant financial support;
- "ocean of creativity" metaphorically represents the vast collection of projects;
- "waves of support" symbolize the monetary pledges by backers;
- "masterminds" refers to project creators.

sql:
SELECT name
FROM projects
WHERE pledged >= goal AND spotlight = 1;

external_knowledge:
- Substantial amount: greater than $100;
- Ongoing projects that haven't reached their targets: live projects with the pledged amount less than the set funding goal;
- Generous backers: users who have pledged more than the substantial amount to any project.

sql:
SELECT MAX(avg_donation) AS highest_average_donation
FROM (
    SELECT creator_id, AVG(average_donation) AS avg_donation
    FROM projects
    GROUP BY creator_id
) AS avg_donations;

SELECT 
    (SELECT COUNT(*) FROM projects) AS total_projects,
    (SELECT COUNT(DISTINCT user_id) FROM project_backers) AS total_backers;

SELECT project_id 
FROM projects 
WHERE pledged >= goal;
